// Propagate to gateway config deny lists
try {
  const config = JSON.parse(readFileSync(configFile, "utf-8"));
  const agentList: any[] = config.agents?.list || [];
  for (const agent of agentList) {
    if (!agent.tools) agent.tools = {};
    if (!agent.tools.deny) agent.tools.deny = [];

    if (!enabled) {
      // Add to deny if not already there
      if (!agent.tools.deny.includes(toolName)) {
        agent.tools.deny.push(toolName);
      }
    } else {
