      agent.tools.deny = agent.tools.deny.filter((t: string) => t !== toolName);
      if (agent.tools.deny.length === 0) delete agent.tools.deny;
    }
  }
  writeFileSync(configFile, JSON.stringify(config, null, 2) + "\n");
} catch (err: any) {
  api.logger?.warn?.(`Failed to propagate tool toggle to config: ${err.message}`);
}
```

### 3. Update `GET /api/mc/tools` response (agents.ts)

The existing response is fine — it reads `tools.json` and returns enabled/disabled state per tool. No changes needed here.

### 4. Update `GET /api/mc/agents` response (agents.ts)

